ALL_SAMPLES = RAW_SAMPLES + ADDITIONAL
random.shuffle(ALL_SAMPLES)

split_idx = int(len(ALL_SAMPLES) * 0.9)
train_samples = ALL_SAMPLES[:split_idx]
val_samples = ALL_SAMPLES[split_idx:]

def to_alpaca(ex: dict) -> dict:
    return {
        "text": (
            f"### Instruction:\n{ex['instruction']}\n\n"
            f"### Response:\n{ex['output']}"
        )
    }

Path("data").mkdir(exist_ok=True)

train_dataset = Dataset.from_list([to_alpaca(x) for x in train_samples])
val_dataset = Dataset.from_list([to_alpaca(x) for x in val_samples])

train_dataset.save_to_disk("data/train")
val_dataset.save_to_disk("data/val")

with open("data/raw_samples.json", "w") as f:
    json.dump(ALL_SAMPLES, f, indent=2)

print(f"Total samples : {len(ALL_SAMPLES)}")
print(f"Train samples : {len(train_samples)}")
print(f"Val samples   : {len(val_samples)}")
print("Saved to data/train and data/val")
